sql:
SELECT event_name, date
FROM racing_events
ORDER BY purse_amount DESC, date DESC;

SELECT event_name, purse_amount
FROM racing_events
ORDER BY purse_amount DESC;

SELECT event_name
FROM racing_events
WHERE purse_amount = (SELECT MAX(purse_amount) FROM racing_events);

SELECT horse_name
FROM horses
ORDER BY horse_name ASC;

external_knowledge:
- In horse racing, winning by a length means the horse has won by a significant margin, which is often considered a notable achievement; 
- A winning margin greater than 1.0 refers to the number of lengths by which a horse has won; 
- Top-performing horses are those with high earnings, typically indicating success in racing; 
- Cumulative earnings refer to the total earnings of a trainer across all their horses, providing insight into their overall success.

sql:
SELECT horse_name
FROM horses
WHERE horse_id IN (SELECT horse_id FROM winners);
